import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import { useAuth } from "../context/useAuth";

const BG_IMAGE = "PLACEHOLDER_B64";

const Login = () => {
  const { login } = useAuth();
  const navigate = useNavigate();

  const [selectedRole, setSelectedRole] = useState("patient");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState("");

  const handleSubmit = async (e) => {
    e.preventDefault();
    setIsLoading(true);
    setError("");

    try {
      const user = await login(email, password);

      if (user.role.toLowerCase() !== selectedRole) {
        setError("Selected role does not match your account.");
        setIsLoading(false);
        return;
      }

      if (user.role === "ADMIN") {
        navigate("/admin/dashboard");
      } else if (user.role === "DOCTOR") {
        navigate("/doctor/dashboard");
      } else if (user.role === "PATIENT") {
        navigate("/patient/dashboard");
      }
    // eslint-disable-next-line no-unused-vars
    } catch (err) {
      setError("Invalid email or password");
    } finally {
      setIsLoading(false);
    }
  };

  const roles = [
    { id: "admin", label: "Admin", color: "from-purple-500 to-indigo-600" },
    { id: "doctor", label: "Doctor", color: "from-blue-500 to-cyan-500" },
    { id: "patient", label: "Patient", color: "from-emerald-500 to-teal-500" }
  ];

  const roleAccent = {
    admin: { border: "#6366f1", bg: "#eef2ff", text: "#4338ca" },
    doctor: { border: "#0ea5e9", bg: "#e0f2fe", text: "#0369a1" },
    patient: { border: "#14b8a6", bg: "#f0fdfa", text: "#0f766e" },
  };

  const accent = roleAccent[selectedRole];

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Lora:wght@400;600&family=DM+Sans:wght@300;400;500;600&display=swap');

        .login-root {
          min-height: 100vh;
          display: flex;
          align-items: center;
          justify-content: center;
          font-family: 'DM Sans', sans-serif;
          padding: 1.5rem;
          position: relative;
          overflow: hidden;
          background: #0a1628;
        }

        .login-bg {
          position: absolute;
          inset: 0;
          background-image: url("data:image/jpeg;base64,");
          background-size: cover;
          background-position: center center;
          background-repeat: no-repeat;
          z-index: 0;
        }

        .login-bg-overlay {
          position: absolute;
          inset: 0;
          background: linear-gradient(
            135deg,
            rgba(5, 15, 40, 0.80) 0%,
            rgba(8, 30, 65, 0.72) 40%,
            rgba(5, 35, 50, 0.78) 100%
          );
          z-index: 1;
          backdrop-filter: blur(1.5px);
        }

        .login-root > .login-split {
          position: relative;
          z-index: 2;
        }

        .login-split {
          display: flex;
          width: 100%;
          max-width: 820px;
          background: #ffffff;
          border-radius: 20px;
          box-shadow: 0 24px 80px rgba(0,0,0,0.55), 0 4px 16px rgba(0,0,0,0.35);
          overflow: hidden;
          position: relative;
          animation: cardIn 0.55s cubic-bezier(0.22,1,0.36,1) both;
        }

        @keyframes cardIn {
          from { opacity: 0; transform: translateY(28px) scale(0.98); }
          to   { opacity: 1; transform: translateY(0) scale(1); }
        }

        /* Left panel */
        .login-panel {
          width: 240px;
          flex-shrink: 0;
          background: linear-gradient(160deg, #0c1c3a 0%, #0f3460 60%, #155e75 100%);
          padding: 2.5rem 1.75rem;
          display: flex;
          flex-direction: column;
          justify-content: space-between;
        }

        .panel-logo {
          display: flex;
          align-items: center;
          gap: 10px;
          margin-bottom: 2.5rem;
        }

        .panel-logo-icon {
          width: 40px;
          height: 40px;
          background: rgba(255,255,255,0.12);
          border-radius: 10px;
          display: flex;
          align-items: center;
          justify-content: center;
          font-size: 20px;
          border: 1px solid rgba(255,255,255,0.18);
        }

        .panel-logo-text {
          font-family: 'Lora', serif;
          font-size: 1.15rem;
          font-weight: 600;
          color: #ffffff;
          line-height: 1.1;
        }

        .panel-logo-sub {
          font-size: 0.6rem;
          color: rgba(255,255,255,0.45);
          font-weight: 400;
          letter-spacing: 0.04em;
          text-transform: uppercase;
        }

        .panel-headline {
          font-family: 'Lora', serif;
          font-size: 1.35rem;
          font-weight: 600;
          color: #ffffff;
          line-height: 1.4;
          margin-bottom: 0.75rem;
        }

        .panel-body {
          font-size: 0.78rem;
          color: rgba(255,255,255,0.5);
          line-height: 1.6;
          margin-bottom: 2rem;
        }

        .panel-badges {
          display: flex;
          flex-direction: column;
          gap: 8px;
        }

        .panel-badge {
          display: flex;
          align-items: center;
          gap: 8px;
          font-size: 0.72rem;
          color: rgba(255,255,255,0.65);
        }

        .panel-badge-dot {
          width: 6px;
          height: 6px;
          border-radius: 50%;
          background: #38bdf8;
          flex-shrink: 0;
        }

        /* Right form panel */
        .login-form-area {
          flex: 1;
          padding: 2.5rem 2.25rem;
          display: flex;
          flex-direction: column;
          justify-content: center;
        }

        .form-heading {
          font-family: 'Lora', serif;
          font-size: 1.45rem;
          font-weight: 600;
          color: #0c1c3a;
          margin-bottom: 0.3rem;
        }

        .form-subheading {
          font-size: 0.8rem;
          color: #64748b;
          margin-bottom: 1.75rem;
        }

        .role-label {
          font-size: 0.72rem;
          font-weight: 600;
          text-transform: uppercase;
          letter-spacing: 0.07em;
          color: #94a3b8;
          margin-bottom: 0.6rem;
        }

        .role-grid {
          display: grid;
          grid-template-columns: repeat(3, 1fr);
          gap: 8px;
          margin-bottom: 1.5rem;
        }

        .role-btn {
          padding: 10px 6px;
          border-radius: 10px;
          border: 1.5px solid #e2e8f0;
          background: #f8fafc;
          cursor: pointer;
          transition: all 0.2s ease;
          display: flex;
          flex-direction: column;
          align-items: center;
          gap: 4px;
        }

        .role-btn:hover {
          border-color: #cbd5e1;
          background: #f1f5f9;
        }

        .role-btn.active {
          border-color: var(--accent-border);
          background: var(--accent-bg);
        }

        .role-icon { font-size: 1.25rem; line-height: 1; }

        .role-text {
          font-size: 0.68rem;
          font-weight: 600;
          color: #475569;
        }

        .role-btn.active .role-text { color: var(--accent-text); }

        .input-group { margin-bottom: 0.85rem; }

        .input-label {
          font-size: 0.72rem;
          font-weight: 600;
          text-transform: uppercase;
          letter-spacing: 0.06em;
          color: #64748b;
          margin-bottom: 0.35rem;
          display: block;
        }

        .input-field {
          width: 100%;
          padding: 10px 14px;
          border-radius: 9px;
          border: 1.5px solid #e2e8f0;
          background: #f8fafc;
          font-size: 0.875rem;
          color: #0f172a;
          font-family: 'DM Sans', sans-serif;
          transition: border-color 0.2s, box-shadow 0.2s;
          box-sizing: border-box;
          outline: none;
        }

        .input-field::placeholder { color: #94a3b8; }

        .input-field:focus {
          border-color: var(--accent-border, #0ea5e9);
          box-shadow: 0 0 0 3px var(--accent-ring, rgba(14,165,233,0.12));
          background: #fff;
        }

        .error-msg {
          font-size: 0.78rem;
          color: #ef4444;
          background: #fff1f2;
          border: 1px solid #fecdd3;
          border-radius: 7px;
          padding: 8px 12px;
          margin-bottom: 0.75rem;
        }

        .submit-btn {
          width: 100%;
          padding: 11px;
          border-radius: 10px;
          border: none;
          cursor: pointer;
          font-size: 0.875rem;
          font-weight: 600;
          font-family: 'DM Sans', sans-serif;
          letter-spacing: 0.02em;
          transition: opacity 0.2s, transform 0.15s;
          background: linear-gradient(135deg, #0c1c3a 0%, #0f3460 100%);
          color: #ffffff;
          margin-top: 0.25rem;
        }

        .submit-btn:hover:not(:disabled) {
          opacity: 0.9;
          transform: translateY(-1px);
        }

        .submit-btn:disabled { opacity: 0.65; cursor: not-allowed; }

        .divider-line {
          height: 1px;
          background: #e2e8f0;
          margin: 1.25rem 0;
        }

        .trust-row {
          display: flex;
          align-items: center;
          gap: 6px;
          font-size: 0.7rem;
          color: #94a3b8;
          justify-content: center;
        }

        .trust-dot { color: #22c55e; font-size: 0.65rem; }

        @media (max-width: 600px) {
          .login-panel { display: none; }
          .login-form-area { padding: 2rem 1.5rem; }
          .login-split { max-width: 420px; }
        }
      `}</style>

      <div className="login-root">
        <div className="login-bg" />
        <div className="login-bg-overlay" />

        <div
          className="login-split"
          style={{
            "--accent-border": accent.border,
            "--accent-bg": accent.bg,
            "--accent-text": accent.text,
            "--accent-ring": accent.bg,
          }}
        >
          {/* Left Panel */}
          <div className="login-panel">
            <div>
              <div className="panel-logo">
                <div>
                  <div className="panel-logo-text">Aroha AI</div>
                  <div className="panel-logo-sub">Medical Platform</div>
                </div>
              </div>
              <div className="panel-headline">Your health records, intelligently managed.</div>
              <div className="panel-body">
                Secure, AI-powered medical record management trusted by clinics and patients alike.
              </div>
            </div>
            <div className="panel-badges">
              {["HIPAA Compliant", "End-to-end Encrypted", "AI-Assisted Insights", "24/7 Access"].map(t => (
                <div className="panel-badge" key={t}>
                  <span className="panel-badge-dot" />
                  {t}
                </div>
              ))}
            </div>
          </div>

          {/* Right Form */}
          <div className="login-form-area">
            <div className="form-heading">Welcome back</div>
            <div className="form-subheading">Sign in to your Aroha AI account</div>

            <div className="role-label">I am a</div>
            <div className="role-grid">
              {roles.map((role) => (
                <button
                  key={role.id}
                  type="button"
                  onClick={() => setSelectedRole(role.id)}
                  className={`role-btn${selectedRole === role.id ? " active" : ""}`}
                >
                  <span className="role-icon">{role.icon}</span>
                  <span className="role-text">{role.label}</span>
                </button>
              ))}
            </div>

            <form onSubmit={handleSubmit}>
              <div className="input-group">
                <label className="input-label">Email address</label>
                <input
                  type="email"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  className="input-field"
                  placeholder="you@example.com"
                  required
                />
              </div>

              <div className="input-group">
                <label className="input-label">Password</label>
                <input
                  type="password"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  className="input-field"
                  placeholder="••••••••"
                  required
                />
              </div>

              {error && <div className="error-msg">⚠ {error}</div>}

              <button type="submit" disabled={isLoading} className="submit-btn">
                {isLoading ? "Signing in…" : "Sign In"}
              </button>
            </form>

            <div className="divider-line" />
            <div className="trust-row">
              <span className="trust-dot">●</span>
              Secured with 256-bit encryption &nbsp;·&nbsp; Data never shared
            </div>
          </div>
        </div>
      </div>
    </>
  );
};

export default Login;